/**
 * @jaskier/i18n — Shared i18next configuration
 *
 * Provides shared language detection settings and default init options
 * used by all Hydra apps (GeminiHydra, OpenAIHydra, GrokHydra, DeepSeekHydra).
 */

import type { InitOptions } from 'i18next';

export const DEFAULT_DETECTION_OPTIONS = {
  order: ['localStorage', 'navigator', 'htmlTag'] as const,
  caches: ['localStorage'] as const,
} satisfies NonNullable<InitOptions['detection']>;

export const SUPPORTED_LANGUAGES = ['en', 'pl'] as const;
export type SupportedLanguage = (typeof SUPPORTED_LANGUAGES)[number];

export const DEFAULT_FALLBACK_LNG: SupportedLanguage = 'en';
export const DEFAULT_NAMESPACE = 'translation';
