/**
 * @jaskier/i18n — Shared translations and i18next initializer
 *
 * Usage:
 *   import { initI18n } from '@jaskier/i18n';
 *   void initI18n(); // uses shared EN/PL translations
 *
 * With app-specific overrides:
 *   void initI18n({
 *     overrides: {
 *       en: { home: { title: 'OpenAIHydra' } },
 *       pl: { home: { title: 'OpenAIHydra' } },
 *     },
 *   });
 */

import i18n from 'i18next';
import LanguageDetector from 'i18next-browser-languagedetector';
import { initReactI18next } from 'react-i18next';

import { DEFAULT_DETECTION_OPTIONS, DEFAULT_FALLBACK_LNG, DEFAULT_NAMESPACE } from './config.js';
import enBase from './locales/en.json';
import plBase from './locales/pl.json';

export type { SupportedLanguage } from './config.js';
export { DEFAULT_DETECTION_OPTIONS, DEFAULT_FALLBACK_LNG, DEFAULT_NAMESPACE, SUPPORTED_LANGUAGES } from './config.js';

/** Raw locale bundles — importable for custom merging */
export const locales = {
  en: enBase,
  pl: plBase,
} as const;

export type LocaleBundle = typeof enBase;

/** Recursively makes all properties optional */
export type DeepPartial<T> = {
  [K in keyof T]?: T[K] extends Record<string, unknown> ? DeepPartial<T[K]> : T[K];
};

/** Deep-merge helper (shallow per top-level key) */
function mergeTranslations<T extends Record<string, unknown>>(base: T, overrides: DeepPartial<T>): T {
  const result = { ...base };
  for (const key of Object.keys(overrides) as (keyof T)[]) {
    const baseVal = base[key];
    const overrideVal = overrides[key];
    if (
      baseVal !== null &&
      typeof baseVal === 'object' &&
      !Array.isArray(baseVal) &&
      overrideVal !== null &&
      typeof overrideVal === 'object' &&
      !Array.isArray(overrideVal)
    ) {
      result[key] = {
        ...(baseVal as Record<string, unknown>),
        ...(overrideVal as Record<string, unknown>),
      } as T[keyof T];
    } else {
      result[key] = overrideVal as T[keyof T];
    }
  }
  return result;
}

export interface InitI18nOptions {
  /**
   * Per-language translation overrides merged on top of the shared bundles.
   * Deep-merged at top-level key granularity (e.g. overriding `home` replaces
   * individual keys within `home`, not the whole `home` object).
   */
  overrides?: {
    en?: DeepPartial<LocaleBundle>;
    pl?: DeepPartial<LocaleBundle>;
  };
  /** Override the i18next namespace (default: 'translation') */
  ns?: string;
}

/**
 * Initialize i18next with shared Jaskier translations.
 * Call this once at app startup (typically in src/i18n/index.ts).
 * Returns the i18next instance.
 */
export function initI18n(options: InitI18nOptions = {}): typeof i18n {
  const { overrides = {}, ns = DEFAULT_NAMESPACE } = options;

  const en = overrides.en ? mergeTranslations(enBase, overrides.en) : enBase;
  const pl = overrides.pl ? mergeTranslations(plBase, overrides.pl) : plBase;

  void i18n
    .use(LanguageDetector)
    .use(initReactI18next)
    .init({
      resources: {
        en: { [ns]: en },
        pl: { [ns]: pl },
      },
      fallbackLng: DEFAULT_FALLBACK_LNG,
      defaultNS: ns,
      interpolation: {
        escapeValue: false,
      },
      detection: DEFAULT_DETECTION_OPTIONS,
    });

  return i18n;
}

export default i18n;
